using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys() =>
        JsonSerializer.Serialize(new[] { "Environment", "MaxRetries", "TimeoutSeconds", "FeatureFlags:DarkMode", "FeatureFlags:BetaAccess" });

    [McpServerTool, Description("Validates whether a configuration key exists and returns its current value.")]
    public static string ValidateConfigKey(
        [Description("The configuration key to validate (e.g. 'MaxRetries')")] string key)
    {
        var settings = JsonSerializer.Deserialize<Dictionary<string, string>>(ConfigResources.GetAllSettings())!;
        return settings.TryGetValue(key, out var value)
            ? $"✅ Key '{key}' exists with value: {value}"
            : $"❌ Key '{key}' does not exist. Available keys: {string.Join(", ", settings.Keys)}";
    }
}

