[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, string> AppSettings = new()
    {
        ["Environment"] = "Production",
        ["MaxRetries"] = "3",
        ["TimeoutSeconds"] = "30",
        ["FeatureFlags:DarkMode"] = "true",
        ["FeatureFlags:BetaAccess"] = "false"
    };

    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns all application configuration settings as JSON.")]
    public static string GetAllSettings() =>
        JsonSerializer.Serialize(AppSettings, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/settings/{key}",
        Name = "Single Setting",
        MimeType = "text/plain"),
     Description("Returns a single configuration value by key.")]
    public static string GetSetting(string key) =>
        AppSettings.TryGetValue(key, out var value)
            ? value
            : throw new KeyNotFoundException($"Setting '{key}' not found.");

    [McpServerResource(
        UriTemplate = "config://app/features",
        Name = "Feature Flags",
        MimeType = "application/json"),
     Description("Returns the current feature flags.")]
    public static string GetFeatureFlags() =>
        JsonSerializer.Serialize(
            AppSettings.Where(kv => kv.Key.StartsWith("FeatureFlags:"))
                       .ToDictionary(kv => kv.Key.Replace("FeatureFlags:", ""), kv => bool.Parse(kv.Value)),
            new JsonSerializerOptions { WriteIndented = true });
}
"}

